const { useState, useEffect, useMemo, useRef } = React;

// ---------- DATA ----------
// Status keys: available | occupied | starters | mains | mainsdone | bill
const NOW = Date.now();
const ago = (mins) => NOW - mins * 60 * 1000;

const TABLES_INIT = [
  // ─── WINDOW SECTION (top strip) — 2-tops along the window ───
  { id: 1, num: "W1", shape: "sq",    capacity: 2, covers: 2, status: "starters",  seatedAt: ago(28), server: "AS", x: 60,  y: 70,  w: 90,  h: 90 },
  { id: 2, num: "W2", shape: "sq",    capacity: 2, covers: 2, status: "occupied",  seatedAt: ago(11), server: "MK", x: 175, y: 70,  w: 90,  h: 90 },
  { id: 3, num: "W3", shape: "sq",    capacity: 2, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 290, y: 70,  w: 90,  h: 90 },
  { id: 4, num: "W4", shape: "sq",    capacity: 2, covers: 2, status: "mains",     seatedAt: ago(54), server: "AS", x: 405, y: 70,  w: 90,  h: 90 },
  { id: 5, num: "W5", shape: "sq",    capacity: 2, covers: 2, status: "mainsdone", seatedAt: ago(82), server: "JR", x: 520, y: 70,  w: 90,  h: 90 },
  { id: 6, num: "W6", shape: "sq",    capacity: 2, covers: 2, status: "bill",      seatedAt: ago(96), server: "MK", x: 635, y: 70,  w: 90,  h: 90 },

  // ─── MAIN HALL (center) — round tops ───
  { id: 7,  num: "12", shape: "round", capacity: 4, covers: 4, status: "occupied",  seatedAt: ago(7),  server: "JR", x: 90,  y: 230, w: 110, h: 110 },
  { id: 8,  num: "14", shape: "round", capacity: 4, covers: 3, status: "starters",  seatedAt: ago(33), server: "AS", x: 230, y: 230, w: 110, h: 110 },
  { id: 9,  num: "16", shape: "round", capacity: 6, covers: 6, status: "mains",     seatedAt: ago(48), server: "MK", x: 380, y: 220, w: 130, h: 130 },
  { id: 10, num: "18", shape: "round", capacity: 4, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 540, y: 230, w: 110, h: 110 },
  { id: 11, num: "20", shape: "round", capacity: 4, covers: 4, status: "mainsdone", seatedAt: ago(76), server: "JR", x: 680, y: 230, w: 110, h: 110 },

  // ─── MAIN HALL ROW 2 — banquettes ───
  { id: 12, num: "22", shape: "sq",    capacity: 6, covers: 5, status: "occupied",  seatedAt: ago(4),  server: "AS", x: 90,  y: 380, w: 130, h: 95 },
  { id: 13, num: "24", shape: "sq",    capacity: 4, covers: 4, status: "starters",  seatedAt: ago(22), server: "MK", x: 240, y: 380, w: 110, h: 95 },
  { id: 14, num: "26", shape: "sq",    capacity: 4, covers: 4, status: "mains",     seatedAt: ago(41), server: "JR", x: 370, y: 380, w: 110, h: 95 },
  { id: 15, num: "28", shape: "sq",    capacity: 8, covers: 7, status: "occupied",  seatedAt: ago(15), server: "AS", x: 500, y: 380, w: 160, h: 95 },
  { id: 16, num: "30", shape: "sq",    capacity: 4, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 680, y: 380, w: 110, h: 95 },

  // ─── BAR (right column) ───
  { id: 17, num: "B1", shape: "round", capacity: 2, covers: 2, status: "occupied",  seatedAt: ago(3),  server: "MK", x: 870, y: 90,  w: 80,  h: 80 },
  { id: 18, num: "B2", shape: "round", capacity: 2, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 870, y: 190, w: 80,  h: 80 },
  { id: 19, num: "B3", shape: "round", capacity: 2, covers: 2, status: "starters",  seatedAt: ago(19), server: "JR", x: 870, y: 290, w: 80,  h: 80 },

  // ─── PATIO (bottom) ───
  { id: 20, num: "P1", shape: "sq",    capacity: 4, covers: 4, status: "mains",     seatedAt: ago(38), server: "AS", x: 90,  y: 560, w: 105, h: 95 },
  { id: 21, num: "P2", shape: "sq",    capacity: 4, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 215, y: 560, w: 105, h: 95 },
  { id: 22, num: "P3", shape: "round", capacity: 6, covers: 6, status: "bill",      seatedAt: ago(108),server: "MK", x: 345, y: 545, w: 125, h: 125 },
  { id: 23, num: "P4", shape: "sq",    capacity: 4, covers: 4, status: "mainsdone", seatedAt: ago(68), server: "JR", x: 495, y: 560, w: 105, h: 95 },
  { id: 24, num: "P5", shape: "sq",    capacity: 4, covers: 0, status: "available", seatedAt: 0,       server: "",   x: 620, y: 560, w: 105, h: 95 },
];

const STATUS_LABELS = {
  available: "Available",
  occupied: "Seated",
  starters: "Starters fired",
  mains: "Mains fired",
  mainsdone: "Mains done",
  bill: "Bill printed",
};
const STATUS_SHORT = {
  available: "Open",
  occupied: "Seated",
  starters: "Starters",
  mains: "Mains",
  mainsdone: "Cleared",
  bill: "Bill",
};
const STATUS_ORDER = ["occupied","starters","mains","mainsdone","bill","available"];

// ---------- HOOKS ----------
function useTick(intervalMs = 1000) {
  const [, setN] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setN(n => n + 1), intervalMs);
    return () => clearInterval(id);
  }, [intervalMs]);
}

function fmtTimer(ms) {
  if (!ms || ms < 0) return "--:--";
  const total = Math.floor(ms / 1000);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  if (h > 0) return `${h}:${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")}`;
  return `${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")}`;
}

function fmtClock(d) {
  let h = d.getHours();
  const m = d.getMinutes();
  const ampm = h >= 12 ? "PM" : "AM";
  h = h % 12 || 12;
  return `${h}:${String(m).padStart(2,"0")} ${ampm}`;
}

// ---------- ICONS ----------
const PersonIcon = () => (
  <svg viewBox="0 0 16 16" fill="currentColor" aria-hidden="true">
    <circle cx="8" cy="5" r="2.6"/>
    <path d="M3 14c0-2.8 2.2-5 5-5s5 2.2 5 5v0H3z"/>
  </svg>
);

// ---------- TABLE TILE ----------
function Table({ t, selected, onClick }) {
  const timerMs = t.status === "available" ? 0 : (Date.now() - t.seatedAt);
  const isRound = t.shape === "round";

  return (
    <div
      className={`table ${isRound ? "round" : "sq"} ${selected ? "selected" : ""}`}
      style={{ left: t.x, top: t.y, width: t.w, height: t.h }}
      onClick={() => onClick(t.id)}
      data-comment-anchor={`table-${t.num}`}
    >
      <div className={`tile s-${t.status}`}>
        {t.server && <div className="t-server" title={`Server ${t.server}`}>{t.server}</div>}

        {isRound ? (
          <div className="t-inner">
            <div className="t-num">{t.num}</div>
            {t.status === "available" ? (
              <>
                <div className="t-empty-r">OPEN · {t.capacity}</div>
              </>
            ) : (
              <>
                <div className="t-covers-row">
                  <PersonIcon /> {t.covers}/{t.capacity}
                </div>
                <div className="t-timer">{fmtTimer(timerMs)}</div>
              </>
            )}
          </div>
        ) : (
          <>
            <div className="t-top">
              <div className="t-num">{t.num}</div>
              <div className="t-covers">
                {t.status === "available"
                  ? <>· {t.capacity} TOP</>
                  : <><PersonIcon /> {t.covers}/{t.capacity}</>}
              </div>
            </div>
            <div className="t-bottom">
              <div className="t-status">{STATUS_SHORT[t.status]}</div>
              {t.status !== "available" && <div className="t-timer">{fmtTimer(timerMs)}</div>}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ---------- LEGEND ----------
function Legend() {
  const items = [
    { key: "available", label: "Available",      bg: "#22c55e" },
    { key: "occupied",  label: "Seated",         bg: "#e94560" },
    { key: "starters",  label: "Starters fired", bg: "#eab308" },
    { key: "mains",     label: "Mains fired",    bg: "#60a5fa" },
    { key: "mainsdone", label: "Mains done",     bg: "#0D1B3E" },
    { key: "bill",      label: "Bill printed",   bg: "#ffffff", isBill: true },
  ];
  return (
    <div className="legend">
      <div className="legend-title">Status</div>
      {items.map(i => (
        <div key={i.key} className="legend-item">
          <div className={`legend-swatch ${i.isBill ? "bill" : ""}`} style={{ background: i.bg }}/>
          <span>{i.label}</span>
        </div>
      ))}
    </div>
  );
}

// ---------- NAVBAR ----------
function Navbar({ now, sectionCounts, activeSection, setActiveSection }) {
  const tabs = ["Floor", "Orders", "Reservations", "Reports", "Settings"];
  return (
    <header className="nav">
      <div className="wordmark">
        <span className="siam">Siam</span>
        <span className="dot"/>
        <span className="epos">EPOS</span>
      </div>
      <div className="nav-tabs">
        {tabs.map(t => (
          <div key={t} className={`nav-tab ${t === "Floor" ? "active" : ""}`}>{t}</div>
        ))}
      </div>
      <div className="nav-spacer"/>
      <div className="clock">
        <span>WED · 7 MAY</span>
        <span className="time">{fmtClock(now)}</span>
      </div>
      <div className="status-badge">
        <span className="status-dot"/>
        <span>SERVICE OPEN · DINNER</span>
      </div>
      <div className="staff">
        <div className="staff-avatar">AS</div>
        <div className="staff-info">
          <div className="staff-name">Anong Sirikul</div>
          <div className="staff-role">Floor Manager</div>
        </div>
      </div>
    </header>
  );
}

// ---------- SUBHEADER STATS ----------
function SubHeader({ tables }) {
  const seated = tables.filter(t => t.status !== "available").length;
  const covers = tables.reduce((s, t) => s + t.covers, 0);
  const capacity = tables.reduce((s, t) => s + t.capacity, 0);
  const open = tables.filter(t => t.status === "available").length;
  const billed = tables.filter(t => t.status === "bill").length;
  const occupancy = Math.round(seated / tables.length * 100);

  return (
    <div className="subheader">
      <h1 className="h1">
        Floor Plan
        <span className="accent">— Dinner Service</span>
      </h1>
      <div className="stat-row">
        <div className="stat">
          <div className="stat-num">{seated}<span style={{color:'rgba(255,255,255,0.4)'}}>/{tables.length}</span></div>
          <div className="stat-label">Tables Seated</div>
        </div>
        <div className="stat">
          <div className="stat-num">{covers}<span style={{color:'rgba(255,255,255,0.4)'}}>/{capacity}</span></div>
          <div className="stat-label">Covers</div>
        </div>
        <div className="stat">
          <div className="stat-num gold-wrap"><span className="gold">{occupancy}</span>%</div>
          <div className="stat-label">Occupancy</div>
        </div>
        <div className="stat">
          <div className="stat-num">{open}</div>
          <div className="stat-label">Available</div>
        </div>
        <div className="stat">
          <div className="stat-num">{billed}</div>
          <div className="stat-label">Closing</div>
        </div>
      </div>
    </div>
  );
}

// ---------- ACTION BAR ----------
function ActionBar({ table, onAction, onClose }) {
  const visible = !!table;
  if (!table) {
    return <div className="action-bar hidden"/>;
  }
  const nextAction = {
    available: { label: "Seat Guests", key: "seat" },
    occupied:  { label: "Fire Starters", key: "fireStarters" },
    starters:  { label: "Fire Mains", key: "fireMains" },
    mains:     { label: "Mark Mains Done", key: "mainsDone" },
    mainsdone: { label: "Print Bill", key: "printBill" },
    bill:      { label: "Close Table", key: "close" },
  }[table.status];

  return (
    <div className={`action-bar ${visible ? "" : "hidden"}`}>
      <div className="ab-table">
        <div className="num">Table {table.num}</div>
        <div className="meta">
          {table.status === "available"
            ? `${table.capacity}-top · open`
            : `${table.covers} covers · ${STATUS_LABELS[table.status]}`}
        </div>
      </div>
      <div className="ab-actions">
        <button className="btn btn-primary" onClick={() => onAction(nextAction.key)}>
          {nextAction.label}
        </button>
        <button className="btn btn-ghost" onClick={() => onAction("viewOrder")}>View Order</button>
        <button className="btn btn-ghost" onClick={() => onAction("transfer")}>Transfer</button>
      </div>
      <button className="ab-close" onClick={onClose} aria-label="Close">×</button>
    </div>
  );
}

// ---------- TOAST ----------
function Toast({ message, show }) {
  return (
    <div className={`toast ${show ? "show" : ""}`}>
      <div className="dot"/>
      <span>{message}</span>
    </div>
  );
}

// ---------- ZONES OVERLAY (architectural decoration) ----------
function FloorChrome() {
  return (
    <>
      {/* Window strip along top */}
      <div className="window-strip"/>
      <div className="zone-label" style={{ left: 32, top: 36 }}>Window</div>

      {/* Main hall divider */}
      <div className="zone-divider h" style={{ top: 195 }}/>
      <div className="zone-label" style={{ left: 32, top: 202 }}>Main Hall</div>

      {/* Patio divider */}
      <div className="zone-divider h" style={{ top: 510 }}/>
      <div className="zone-label" style={{ left: 32, top: 518 }}>Patio</div>

      {/* Bar column divider */}
      <div className="zone-divider v" style={{ left: 840 }}/>
      <div className="zone-label" style={{ left: 870, top: 36 }}>Bar</div>

      {/* Bar counter graphic at bottom of bar column */}
      <div className="bar-counter" style={{ left: 855, top: 400, width: 110, height: 220 }}>
        <span style={{ writingMode: 'vertical-rl', transform: 'rotate(180deg)' }}>BAR COUNTER</span>
      </div>

      {/* Kitchen pass at right edge */}
      <div className="kitchen-pass" style={{ left: 855, top: 640, width: 110, height: 50 }}>
        KITCHEN
      </div>

      {/* Entrance hint */}
      <div className="zone-label" style={{ left: 360, bottom: 12, top: 'auto' }}>↓ Entrance</div>
    </>
  );
}

// ---------- APP ----------
function App() {
  useTick(1000); // re-render every second for live timers
  const [tables, setTables] = useState(TABLES_INIT);
  const [selectedId, setSelectedId] = useState(null);
  const [now, setNow] = useState(new Date());
  const [toast, setToast] = useState({ show: false, message: "" });
  const toastTimer = useRef(null);

  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 30000);
    return () => clearInterval(id);
  }, []);

  const selected = tables.find(t => t.id === selectedId) || null;

  const showToast = (message) => {
    setToast({ show: true, message });
    clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(t => ({ ...t, show: false })), 2400);
  };

  const handleAction = (key) => {
    if (!selected) return;
    setTables(prev => prev.map(t => {
      if (t.id !== selected.id) return t;
      switch (key) {
        case "seat":         return { ...t, status: "occupied",  seatedAt: Date.now(), covers: t.capacity };
        case "fireStarters": return { ...t, status: "starters" };
        case "fireMains":    return { ...t, status: "mains" };
        case "mainsDone":    return { ...t, status: "mainsdone" };
        case "printBill":    return { ...t, status: "bill" };
        case "close":        return { ...t, status: "available", seatedAt: 0, covers: 0, server: "" };
        default: return t;
      }
    }));
    const labels = {
      seat: "Guests seated",
      fireStarters: "Starters fired to kitchen",
      fireMains: "Mains fired to kitchen",
      mainsDone: "Mains marked complete",
      printBill: "Bill printed",
      close: "Table closed",
      viewOrder: "Opening order ticket…",
      transfer: "Transfer flow opened",
    };
    showToast(`${labels[key] || "Action"} · Table ${selected.num}`);
    if (key === "close") setSelectedId(null);
  };

  return (
    <div className="app">
      <Navbar now={now}/>
      <SubHeader tables={tables}/>
      <div className="floor-wrap">
        <div className="section-tabs">
          <div className="section-tab active">All Floor <span className="count">{tables.length}</span></div>
          <div className="section-tab">Window <span className="count">6</span></div>
          <div className="section-tab">Main Hall <span className="count">10</span></div>
          <div className="section-tab">Bar <span className="count">3</span></div>
          <div className="section-tab">Patio <span className="count">5</span></div>
          <div className="section-tab">Private Dining <span className="count">2</span></div>
        </div>

        <div className="floor">
          <FloorChrome/>
          {tables.map(t => (
            <Table
              key={t.id}
              t={t}
              selected={t.id === selectedId}
              onClick={(id) => setSelectedId(id === selectedId ? null : id)}
            />
          ))}
        </div>

        <Legend/>
      </div>

      <ActionBar
        table={selected}
        onAction={handleAction}
        onClose={() => setSelectedId(null)}
      />
      <Toast message={toast.message} show={toast.show}/>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(<App/>);

